import * as React from "react"
import { graphql, useStaticQuery, Link } from "gatsby"
import { useLocation } from "@reach/router"
import { container } from "./ui.css"
import { poemMenuLink, poemMenuLinkActive, poemMenuItem, poemMenuText, poemGrid } from "./poem-list.css"

type Poem = {
  id: string
  title: string
  slug: string
  media?: {
    mimeType?: string
  }
}

const navLinks = [
  { to: "/", label: "Home" },
  { to: "/biography", label: "Biography" },
  { to: "/published-work", label: "Published Work" },
  { to: "/e-books", label: "E-books" },
]

const PoemList: React.FC<{ type?: string }> = ({ type }) => {
  const location = useLocation()
  const data = useStaticQuery(graphql`
    query PoemListQuery {
      allContentfulPoem(sort: { title: ASC }) {
        nodes {
          id
          title
          slug
          media {
            mimeType
          }
        }
      }
    }
  `)

  const poems: Poem[] = data?.allContentfulPoem?.nodes || []
  const showNav = type !== "home" && type !== "poems"
  const isGrid = type === "poems"

  if (!poems.length) {
    return <nav className={container}><p>No poems found.</p></nav>
  }

  return (
    <nav className={container} aria-label="Poems menu">
      <ul className={isGrid ? poemGrid : undefined} style={isGrid ? {} : { listStyle: "none", margin: 0, padding: 0 }}>
        {showNav && navLinks.map(({ to, label }) => (
          <li key={to} className={poemMenuItem}>
            <Link to={to} className={poemMenuLink}>{label}</Link>
          </li>
        ))}
        {poems.map((p) => {
          const isActive = location.pathname === `/poems/${p.slug}` || location.pathname === `/poems/${p.slug}/`
          const hasAudio = p.media?.mimeType?.startsWith("audio")
          return (
            <li key={p.id} className={poemMenuItem}>
              <Link
                to={`/poems/${p.slug}`}
                className={`${poemMenuLink}${isActive ? ` ${poemMenuLinkActive}` : ""}`}
                style={{ display: "flex", alignItems: "flex-start" }}
              >
                <span
                  title={hasAudio ? "Audio available" : undefined}
                  style={{ width: "1.2rem", flexShrink: 0, fontSize: "0.9em", color: "#b35000", visibility: hasAudio ? "visible" : "hidden" }}
                >♪</span>
                <span className={poemMenuText}>{p.title || "Untitled"}</span>
              </Link>
            </li>
          )
        })}
      </ul>
    </nav>
  )
}

export default PoemList
