import { Link as GatsbyLink } from "gatsby"
import { GatsbyImage, getImage } from "gatsby-plugin-image"
import isAbsoluteURL from "is-absolute-url"
import * as React from "react"
import * as styles from "./ui.css"

export const cx = (...args: (string | boolean | undefined)[]): string => 
  args.filter(Boolean).join(" ")

interface BaseProps extends React.HTMLAttributes<HTMLElement> {
  as?: React.ElementType
  cx?: (string | boolean)[]
}

export function Base({
  as: Component = "div",
  cx: _cx = [],
  className,
  ...props
}: BaseProps) {
  return <Component className={cx(...(_cx as (string | boolean)[]), className)} {...props} />
}

interface ContainerProps extends React.HTMLAttributes<HTMLDivElement> {
  width?: "normal" | "narrow" | "wide"
}

export function Container({ width = "normal", ...props }: ContainerProps) {
  return <Base cx={[styles.containers[width]]} {...props} />
}

interface FlexProps extends React.HTMLAttributes<HTMLDivElement> {
  as?: React.ElementType
  variant?: string
  gap?: number
  gutter?: number
  wrap?: boolean
  responsive?: boolean
  marginY?: number
  alignItems?: string
  cx?: (string | boolean)[]
}

export function Flex({
  variant,
  gap = 3,
  gutter,
  wrap,
  responsive,
  marginY,
  alignItems,
  cx: _cx = [],
  ...props
}: FlexProps) {
  return (
    <Base
      cx={[
        styles.flex,
        variant && styles.flexVariants[variant],
        responsive && styles.flexVariants.responsive,
        wrap && styles.flexVariants.wrap,
        gutter && styles.gutter[gutter],
        gutter ? styles.flexGap[0] : styles.flexGap[gap],
        marginY && styles.marginY[marginY],
        alignItems && styles.flexVariants[alignItems],
        ..._cx,
      ]}
      {...props}
    />
  )
}

interface BoxProps extends React.HTMLAttributes<HTMLDivElement> {
  as?: React.ElementType
  width?: string
  background?: string
  padding?: number
  paddingY?: number
  radius?: string
  center?: boolean
  order?: number
  cx?: (string | boolean)[]
}

export function Box({
  width = "full",
  background,
  padding,
  paddingY,
  radius,
  center = false,
  order,
  cx: _cx = [],
  ...props
}: BoxProps) {
  return (
    <Base
      cx={[
        styles.widths[width],
        background && styles.backgrounds[background],
        padding && styles.padding[padding],
        paddingY && styles.paddingY[paddingY],
        radius && styles.radii[radius],
        center && styles.box.center,
        order && styles.order[order],
        ..._cx,
      ]}
      {...props}
    />
  )
}

export function FlexList(props: FlexProps) {
  return <Flex as="ul" cx={[styles.list]} {...props} />
}

export function List(props: React.HTMLAttributes<HTMLUListElement>) {
  return <Base as="ul" cx={[styles.list]} {...props} />
}

interface SpaceProps extends React.HTMLAttributes<HTMLDivElement> {
  size?: string | number
}

export function Space({ size = "auto", ...props }: SpaceProps) {
  return <Base cx={[styles.margin[size]]} {...props} />
}

interface NudgeProps extends React.HTMLAttributes<HTMLDivElement> {
  left?: number
  right?: number
  top?: number
  bottom?: number
}

export function Nudge({ left, right, top, bottom, ...props }: NudgeProps) {
  return (
    <Base
      cx={[
        left && styles.marginLeft[-left],
        right && styles.marginRight[-right],
        top && styles.marginTop[-top],
        bottom && styles.marginBottom[-bottom],
      ]}
      {...props}
    />
  )
}

export function Section(props: React.HTMLAttributes<HTMLElement>) {
  return <Box as="section" className={styles.section} {...props} />
}

interface TextProps extends React.HTMLAttributes<HTMLElement> {
  as?: React.ElementType
  variant?: string
  center?: boolean
  bold?: boolean
}

export function Text({
  variant = "body",
  center = false,
  bold = false,
  ...props
}: TextProps) {
  return (
    <Base
      cx={[
        styles.text[variant],
        center && styles.text.center,
        bold && styles.text.bold,
      ]}
      {...props}
    />
  )
}

export function SuperHeading(props: TextProps) {
  return <Text as="h1" variant="superHeading" {...props} />
}

export function Heading(props: TextProps) {
  return <Text as="h2" variant="heading" {...props} />
}

export function Subhead(props: TextProps) {
  return <Text as="h3" variant="subhead" {...props} />
}

export function Kicker(props: TextProps) {
  return <Text variant="kicker" {...props} />
}

interface LinkProps extends React.AnchorHTMLAttributes<HTMLAnchorElement> {
  to?: string
  href?: string
}

export function Link({ to, href, ...props }: LinkProps) {
  const url = href || to || ""
  if (isAbsoluteURL(url)) {
    return (
      // eslint-disable-next-line jsx-a11y/anchor-has-content
      <a href={url} className={styles.link} {...props} />
    )
  }
  return <GatsbyLink to={url} className={styles.link} {...props} />
}

export function NavLink(props: LinkProps) {
  return <Base as={Link} cx={[styles.navlink]} {...props} />
}

export function NavButtonLink(props: React.ButtonHTMLAttributes<HTMLButtonElement>) {
  return <Base as="button" cx={[styles.navButtonlink]} {...props} />
}

interface ButtonProps extends LinkProps {
  variant?: string
}

export function Button({ variant = "primary", ...props }: ButtonProps) {
  return <Base as={Link} cx={[styles.buttons[variant]]} {...props} />
}

interface LinkItem {
  id: string
  href: string
  text: string
}

interface ButtonListProps extends React.HTMLAttributes<HTMLUListElement> {
  links?: LinkItem[]
  reversed?: boolean
}

export function ButtonList({ links = [], reversed = false, ...props }: ButtonListProps) {
  const getVariant = (i: number) => {
    if (reversed) {
      return i === 0 ? "reversed" : "linkReversed"
    }
    return i === 0 ? "primary" : "link"
  }
  return (
    <FlexList marginY={4} {...props}>
      {links &&
        links.map((link, i) => (
          <li key={link.id}>
            <Button href={link.href} variant={getVariant(i)}>
              {link.text}
            </Button>
          </li>
        ))}
    </FlexList>
  )
}

export function CTALink(props: LinkProps) {
  return <Base as={Link} cx={[styles.ctaLink]} {...props} />
}

interface LinkListProps extends React.HTMLAttributes<HTMLUListElement> {
  links?: LinkItem[]
}

export function LinkList({ links = [], ...props }: LinkListProps) {
  return (
    <FlexList {...props}>
      {links &&
        links.map((link, i) => (
          <li key={link.id}>
            <CTALink href={link.href}>{link.text}</CTALink>
          </li>
        ))}
    </FlexList>
  )
}

export function Blockquote(props: React.BlockquoteHTMLAttributes<HTMLQuoteElement>) {
  return <Base as="blockquote" cx={[styles.blockquote]} {...props} />
}

interface AvatarProps {
  alt: string
  image: any
}

export function Avatar({ alt, image }: AvatarProps) {
  return (
    <GatsbyImage alt={alt} image={getImage(image)} className={styles.avatar} />
  )
}

interface LogoProps {
  alt: string
  image: any
  size?: "small" | "medium" | "large"
}

export function Logo({ alt, image, size = "small" }: LogoProps) {
  return (
    <GatsbyImage
      alt={alt}
      image={getImage(image)}
      className={styles.logos[size]}
    />
  )
}

interface IconProps {
  alt: string
  image: any
  size?: "small" | "medium" | "large"
}

export function Icon({ alt, image, size = "medium" }: IconProps) {
  return (
    <GatsbyImage
      alt={alt}
      image={getImage(image)}
      className={styles.icons[size]}
    />
  )
}

export function IconLink(props: LinkProps) {
  return <NavLink cx={[styles.iconLink]} {...props} />
}

export function InteractiveIcon(props: React.ButtonHTMLAttributes<HTMLButtonElement>) {
  return <Base as="button" cx={[styles.interactiveIcon]} {...props} />
}

export function VisuallyHidden(props: React.HTMLAttributes<HTMLSpanElement>) {
  return <Base as="span" cx={[styles.visuallyHidden]} {...props} />
}

export function BlockLink(props: LinkProps) {
  return <Link className={styles.blockLink} {...props} />
}
