import * as React from "react"
import { graphql } from "gatsby"
import Layout from "../components/layout"
import Fallback from "../components/fallback"
import PoemsMenu from "../components/poem-list"
import { BLOCKS, MARKS, INLINES } from '@contentful/rich-text-types'
import { renderRichText } from 'gatsby-source-contentful/rich-text'
import SEOHead from "../components/head"

interface RichTextOptions {
  renderMark: {
    [key: string]: (text: React.ReactNode) => JSX.Element
  }
  renderNode: {
    [key: string]: (node: any, children: React.ReactNode) => JSX.Element
  }
}

const options: RichTextOptions = {
    renderMark: {
      [MARKS.BOLD]: text => <b className="font-bold">{text}</b>,
      [MARKS.ITALIC]: text => <em className="font-italic">{text}</em>,
    },
    renderNode: {
      [BLOCKS.PARAGRAPH]: (node, children) => <p className="mb-4">{children}</p>,
      [BLOCKS.HEADING_2]: (node, children) => <h2 className="text-2xl mt-6 mb-2">{children}</h2>,
      [BLOCKS.EMBEDDED_ASSET]: (node) => {
        // Handle embedded images/assets here using Gatsby Image components if needed
        const { title, description, file } = node.data.target.fields;
        const url = file['en-US'].url; // Example for default locale
        return <img src={url} alt={description || title} className="my-4 mx-auto" />;
      },
      [INLINES.ASSET_HYPERLINK]: (node, children) => {
        const target = node.data.target
        const url = target?.fields?.file?.['en-US']?.url || target?.file?.url
        if (!url) return <>{children}</>
        const href = url.startsWith('//') ? `https:${url}` : url
        return <a href={href} target="_blank" rel="noopener noreferrer">{children}</a>
      },
    },
  }

interface HomepageProps {
  data: {
    homepage: {
      title: string
      description?: string
      images: Array<{
        url?: string
      }>
      content: {
        raw: string
      }
      content2: {
        raw: string
      }
    }
  }
}

export default function Homepage(props: HomepageProps) {
  const { homepage } = (props && props.data) || {}

  if (!homepage) {
    return (
      <div className="wrapper">
        <Layout>
          <Fallback />
        </Layout>
      </div>
    )
  }

  const { title, images, content, content2 } = homepage
  const imageUrl = images?.[0]?.url || null

  return (
      <Layout>
        <div className="wrapper home">
          <h1>Selwyn Pritchard</h1>
          <h4>4 August 1933 &ndash; 30 June 2005</h4>
          <div className="content">
            {content && renderRichText(content, options)}
            <div className="MenuImageContainer">
                <div className="poemsMenuContainer">
                  <PoemsMenu type="home" />  
                 </div>
                 <div className="portrait">
                  {imageUrl && <img src={imageUrl} alt={title} />}
                </div>
            </div>
          </div>
          
          {content2 && renderRichText(content2, options)}
        </div>
      </Layout>
    
  )
}
export const Head = (props: HomepageProps) => {
  const { homepage } = props.data
  const image = homepage?.images?.[0]?.url ? { url: homepage.images[0].url } : undefined
  return <SEOHead title={homepage?.title} description={homepage?.description} image={image} />
}

export const query = graphql`
  {
    homepage: contentfulPage(id: { eq: "fa3cc20f-8475-59ef-adf3-49a62d669b42" }) {
      id
      title
      description
      images {
        url
      }
      content {
        raw
      }
      content2 {
        raw
      }
    }
  }
`
