import * as React from "react"
import { useStaticQuery, graphql, Link } from "gatsby"
import { useLocation } from "@reach/router"

const PoemNavDropdown: React.FC = () => {
  const [isOpen, setIsOpen] = React.useState(false)
  const location = useLocation()

  const data = useStaticQuery(graphql`
    query PoemNavDropdownQuery {
      allContentfulPoem(sort: { title: ASC }) {
        nodes {
          id
          title
          slug
        }
      }
    }
  `)

  const poems = data?.allContentfulPoem?.nodes || []

  return (
    <div className="poemDropdown">
      <button
        className="poemDropdownTrigger"
        onClick={() => setIsOpen((prev) => !prev)}
        aria-expanded={isOpen}
        aria-label={isOpen ? "Close poems menu" : "Open poems menu"}
      >
        Poems <span className="poemDropdownArrow">{isOpen ? "▲" : "▼"}</span>
      </button>
      {isOpen && (
        <ul className="poemDropdownMenu" role="menu">
          {poems.map((poem: { id: string; title: string; slug: string }) => {
            const isActive =
              location.pathname === `/poems/${poem.slug}` ||
              location.pathname === `/poems/${poem.slug}/`
            return (
              <li key={poem.id} role="none">
                <Link
                  to={`/poems/${poem.slug}`}
                  className={`poemDropdownLink${isActive ? " poemDropdownLinkActive" : ""}`}
                  onClick={() => setIsOpen(false)}
                  role="menuitem"
                >
                  {poem.title}
                </Link>
              </li>
            )
          })}
        </ul>
      )}
    </div>
  )
}

export default PoemNavDropdown
